// Perspective projection parameters:
// d = distance from camera to view plane (focal length)
// (xc, yc, zc) = point in camera coordinates

// Simple perspective projection:
x_p = d * xc / zc
y_p = d * yc / zc

// Homogeneous coordinate representation:
// [x_h] [d 0 0 0] [xc]
// [y_h] = [0 d 0 0] [yc]
// [z_h] [0 0 A B] [zc]
// [w_h] [0 0 -1 0] [1 ]

// After perspective division:
x_p = x_h / w_h = (d * xc) / (-zc)
y_p = y_h / w_h = (d * yc) / (-zc)
z_p = z_h / w_h = ... (for z-buffer)

// Complete perspective matrix:
FUNCTION perspectiveMatrix(fov, aspect, near, far):
 f = 1.0 / tan(fov / 2)

 // Column-major matrix
 matrix[0][0] = f / aspect
 matrix[1][1] = f
 matrix[2][2] = (far + near) / (near - far)
 matrix[2][3] = (2 * far * near) / (near - far)
 matrix[3][2] = -1
 matrix[3][3] = 0

 RETURN matrix

